// ─── Task #34 — ME (Musical Effect) ──────────────────────────────────────

/// <summary>
/// Efeito Musical (ME): interrompe a BGM actual, toca um clip não-repetitivo
/// (ex: fanfarra de vitória, jingle de missão) e restaura automaticamente a
/// BGM original quando o clip termina ou quando o NPC é desactivado.
///
/// Diferente de Action_PlayBGM:
///   • Guarda a BGM actual antes de substituir.
///   • Restaura-a quando o ME termina (com restoreFadeTime).
///   • Suporta "waitForMe = true" para bloquear as ações seguintes até o ME acabar.
///   • Se o jogo mudar de cena durante o ME, a restauração não é necessária
///     (a nova cena inicia a sua própria BGM).
///
/// Fluxo típico num evento:
///   1. Action_PlayME (waitForMe = true) → toca o jingle e espera
///   2. Action_Dialogue "Obtiveste a runa!"
///   3. ... próximas ações
/// </summary>
[System.Serializable]
public class Action_PlayME : NpcAction
{
    [Tooltip("Clip do Musical Effect (não repetitivo).")]
    public AudioClip clip;

    [Tooltip("Fade-out aplicado à BGM antes de iniciar o ME.")]
    public float stopBgmFadeTime = 0.3f;

    [Tooltip("Se activo, aguarda que o ME termine (baseado em clip.length) antes de avançar para a próxima ação. Recomendado para jingles curtos.")]
    public bool waitForMe = true;

    [Tooltip("Tempo de fade-in ao restaurar a BGM original após o ME. 0 = instantâneo.")]
    public float restoreFadeTime = 1f;

    [Tooltip("Se activo, restaura automaticamente a BGM original após o ME terminar. Desactivar se a BGM seguinte for controlada por outro sistema (ex: MusicZone).")]
    public bool restoreBgmAfter = true;

    public override IEnumerator Execute(NpcController npc)
    {
        if (clip == null) yield break;

        var am = AudioManager.Instance;
        if (am == null) yield break;

        // Guardar BGM antes de a interromper.
        AudioClip savedBgm = am.CurrentBgmClip;

        // Parar BGM e tocar o ME (como SE não-repetitivo, sem loop).
        am.StopBGM(stopBgmFadeTime);
        if (stopBgmFadeTime > 0f)
            yield return NpcActionUtil.Wait(stopBgmFadeTime);

        am.PlayBGM(clip, 0f, false);

        if (waitForMe)
            yield return NpcActionUtil.Wait(clip.length);

        if (restoreBgmAfter)
            am.PlayBGM(savedBgm, restoreFadeTime);
    }
}

